import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'node execution test',
    parameters: {}
  }
});

export default workflow('node-execution-test', 'Node Execution Test')
  .add(manualTrigger)
  .to(setNode);
